#!/usr/bin/env python3
"""Extract rbfd_ordain wall-clock durations from rbw-fO log files.

Output (TSV to stdout):
  log_basename<TAB>vessel<TAB>operation<TAB>start<TAB>end<TAB>duration_sec

operation is one of: conjure, mirror, about+vouch, vouch
"""

import re
import sys
import os
from datetime import datetime

TS_RE = re.compile(r'^\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\]')
EVENT_RE = re.compile(
    r'rbfd_ordain\S* (Loaded vessel|Building vessel image|Conjure: SUCCESS|'
    r'Vouch: SUCCESS|Mirror: SUCCESS|About\+Vouch: SUCCESS)'
)
VESSEL_RE = re.compile(r'(Loaded vessel|Building vessel image): (\S+)')


def parse_events(path):
    events = []  # list of (ts_str, event_str, vessel_or_None)
    with open(path, encoding='utf-8', errors='replace') as f:
        for line in f:
            tsm = TS_RE.match(line)
            if not tsm:
                continue
            evm = EVENT_RE.search(line)
            if not evm:
                continue
            vessel = None
            vm = VESSEL_RE.search(line)
            if vm:
                vessel = vm.group(2)
            events.append((tsm.group(1), evm.group(1), vessel))
    return events


def to_epoch(ts_str):
    return int(datetime.strptime(ts_str, "%Y-%m-%d %H:%M:%S").timestamp())


def first_with_event(events, want, after_ts=None):
    for ts, ev, vessel in events:
        if ev == want and (after_ts is None or ts >= after_ts):
            return ts, vessel
    return None, None


def vessel_name(events):
    for _, _, v in events:
        if v:
            return v
    return ""


def emit(base, vessel, op, start, end):
    s = to_epoch(start)
    e = to_epoch(end)
    print(f"{base}\t{vessel}\t{op}\t{start}\t{end}\t{e - s}")


def process(path):
    base = os.path.basename(path).replace('.txt', '')
    events = parse_events(path)
    if not events:
        return
    vessel = vessel_name(events)
    has_conjure = any(e[1] == "Conjure: SUCCESS" for e in events)
    has_mirror = any(e[1] == "Mirror: SUCCESS" for e in events)
    has_about_vouch = any(e[1] == "About+Vouch: SUCCESS" for e in events)
    has_vouch = any(e[1] == "Vouch: SUCCESS" for e in events)

    if has_conjure:
        s, _ = first_with_event(events, "Building vessel image")
        e, _ = first_with_event(events, "Conjure: SUCCESS")
        if s and e:
            emit(base, vessel, "conjure", s, e)
    if has_mirror:
        s, _ = first_with_event(events, "Loaded vessel")
        e, _ = first_with_event(events, "Mirror: SUCCESS")
        if s and e:
            emit(base, vessel, "mirror", s, e)
    if has_about_vouch:
        s, _ = first_with_event(events, "Loaded vessel")
        e, _ = first_with_event(events, "About+Vouch: SUCCESS")
        if s and e:
            emit(base, vessel, "about+vouch", s, e)
    if has_vouch:
        anchor = None
        if has_conjure:
            anchor, _ = first_with_event(events, "Conjure: SUCCESS")
        elif has_mirror:
            anchor, _ = first_with_event(events, "Mirror: SUCCESS")
        elif has_about_vouch:
            anchor, _ = first_with_event(events, "About+Vouch: SUCCESS")
        s, _ = first_with_event(events, "Loaded vessel", after_ts=anchor)
        if not s:
            s, _ = first_with_event(events, "Loaded vessel")
        e, _ = first_with_event(events, "Vouch: SUCCESS")
        if s and e:
            emit(base, vessel, "vouch", s, e)


if __name__ == "__main__":
    for p in sys.argv[1:]:
        process(p)

